// ============================================================================
// AI Response Parser & Cleaner
// Purpose: Extract image URLs, remove annotations, clean ANSI codes, parse markdown
// ============================================================================

// Get AI response from multiple possible input fields
const aiResponse = 
    $input.item.json.output || 
    $input.item.json.message || 
    $input.item.json.response || 
    $input.item.json.text || 
    '';

// If no response, return empty
if (!aiResponse || typeof aiResponse !== 'string') {
    return [{
        json: {
            message: '',
            imageUrl: null,
            hasImage: false
        }
    }];
}

// ============================================================================
// STEP 1: Remove ANSI escape codes and annotations
// ============================================================================
function cleanAnnotations(text) {
    let cleaned = text;

    // Remove ANSI escape codes (e.g., [32m[1m[0m)
    cleaned = cleaned.replace(/\[\d+m/g, '');
    cleaned = cleaned.replace(/\x1b\[\d+m/g, ''); // Alternative ANSI format

    // Remove empty square brackets
    cleaned = cleaned.replace(/\[\s*\]/g, '');

    // Remove annotation patterns like [thought], [reasoning], [internal], etc.
    cleaned = cleaned.replace(/\[[a-zA-Z_]+\]/g, '');

    // Remove multiple consecutive newlines (keep max 2)
    cleaned = cleaned.replace(/\n{3,}/g, '\n\n');

    return cleaned;
}

// ============================================================================
// STEP 2: Extract image URL from various formats
// ============================================================================
function extractImageUrl(text) {
    let imageUrl = null;
    let cleanedText = text;

    // Pattern 1: ||IMG:url|| format (your custom format)
    const customPattern = /\|\|IMG:(.*?)\|\|/;
    const customMatch = text.match(customPattern);
    if (customMatch) {
        imageUrl = customMatch[1].trim();
        cleanedText = text.replace(customPattern, '').trim();
        return { imageUrl, cleanedText };
    }

    // Pattern 2: Markdown image format ![alt](url)
    const markdownPattern = /!\[.*?\]\((https?:\/\/[^\)]+)\)/;
    const markdownMatch = text.match(markdownPattern);
    if (markdownMatch) {
        imageUrl = markdownMatch[1].trim();
        // Remove the entire markdown image syntax
        cleanedText = text.replace(markdownPattern, '').trim();
        return { imageUrl, cleanedText };
    }

    // Pattern 3: Raw URL starting with https://www.buyfromturkeynj.com/image/
    const urlPattern = /(https?:\/\/www\.buyfromturkeynj\.com\/image\/[^\s<>\)]+\.(?:jpg|jpeg|png|gif|webp))/i;
    const urlMatch = text.match(urlPattern);
    if (urlMatch) {
        imageUrl = urlMatch[1].trim();
        // Remove the URL from text
        cleanedText = text.replace(urlPattern, '').trim();
        return { imageUrl, cleanedText };
    }

    // Pattern 4: Generic image URL (fallback)
    const genericUrlPattern = /(https?:\/\/[^\s<>\)]+\.(?:jpg|jpeg|png|gif|webp))/i;
    const genericMatch = text.match(genericUrlPattern);
    if (genericMatch) {
        imageUrl = genericMatch[1].trim();
        cleanedText = text.replace(genericUrlPattern, '').trim();
        return { imageUrl, cleanedText };
    }

    // No image found
    return { imageUrl: null, cleanedText };
}

// ============================================================================
// STEP 3: Process the response
// ============================================================================

// First, clean annotations
let processedText = cleanAnnotations(aiResponse);

// Then, extract image URL
const { imageUrl, cleanedText } = extractImageUrl(processedText);

// Final cleanup
let finalMessage = cleanedText
    .replace(/\n{3,}/g, '\n\n')  // Remove excessive newlines
    .trim();

// ============================================================================
// STEP 4: Return formatted output for n8n
// ============================================================================
return [{
    json: {
        message: finalMessage,
        imageUrl: imageUrl,
        hasImage: imageUrl !== null,
        // Optional: Include original for debugging
        // originalOutput: aiResponse
    }
}];
